# USUÁRIOS — users.json no GitHub
# ════════════════════════════════════════════════════════════════
def load_users():
    if os.path.exists(USERS_FILE):
        with open(USERS_FILE,"r",encoding="utf-8") as f:
            return json.load(f)
    # Default se não existir
    return {
        "ADMIN": {
            "senha_hash": hash_senha("admin2025"),
            "perfil": "gestor",
            "nome": "Administrador",
            "ultimo_acesso": None
        },
        "GERENTE": {
            "senha_hash": hash_senha("gerente2025"),
            "perfil": "gerente",
            "nome": "Gerente",
            "ultimo_acesso": None
        }
    }

def save_users(users):
    os.makedirs(DATA_DIR, exist_ok=True)
    with open(USERS_FILE,"w",encoding="utf-8") as f:
        json.dump(users, f, ensure_ascii=False, indent=2)

def registrar_acesso(login):
    users = st.session_state.get("users_db", load_users())
    if login in users:
        users[login]["ultimo_acesso"] = datetime.datetime.now().isoformat()
        save_users(users)
        st.session_state.users_db = users

# ════════════════════════════════════════════════════════════════
# CARREGAMENTO DE DADOS
# ════════════════════════════════════════════════════════════════
@st.cache_data(show_spinner=False)
def load_area(src):
    if isinstance(src, BytesIO): src.seek(0)
    raw = pd.read_excel(src, header=None)

    # Detectar linha de header — procura linha com "VENDEDOR" ou "CONSULTOR" ou "REGIÃO"
    header_row = 0
    for i in range(min(5, len(raw))):
        vals = raw.iloc[i].astype(str).str.upper().tolist()
        if any(k in v for v in vals for k in ["VENDED","CONSUL","REGI","MUNIC"]):
            header_row = i
            break

    if isinstance(src, BytesIO): src.seek(0)
    df = pd.read_excel(src, header=header_row)
    df.columns = [str(c).strip() for c in df.columns]

    # Mapear colunas pelo nome
    col_map = {}
    for c in df.columns:
        cu = str(c).upper()
        if any(k in cu for k in ["VENDED","CONSUL"]): col_map[c] = "Consultor"
        elif "REGI" in cu:    col_map[c] = "Regiao"
        elif "MUNIC" in cu:   col_map[c] = "Municipio"
        elif "BAIRRO" in cu:  col_map[c] = "Bairro"
        elif "CEP" in cu and ("INIC" in cu or "INÍC" in cu): col_map[c] = "CEP_Inicial"
        elif "CEP" in cu and ("FIN" in cu or "FINA" in cu):  col_map[c] = "CEP_Final"
    df = df.rename(columns=col_map)

    # Garantir todas as colunas necessárias
    for col in ["Regiao","Municipio","Bairro","Consultor","CEP_Inicial","CEP_Final"]:
        if col not in df.columns: df[col] = ""

    # Limpar e normalizar
    df = df[df["Consultor"].astype(str).str.strip().str.upper() != "NAN"].copy()
    df = df[df["Consultor"].astype(str).str.strip() != ""].copy()
    df["Consultor"]      = df["Consultor"].fillna("ZONA LIVRE").apply(norm_str)
    df["Municipio_norm"] = df["Municipio"].apply(norm_str)
    df["Bairro_norm"]    = df["Bairro"].apply(lambda x: norm_str(x) if pd.notna(x) else "")
    df["CEP_ini_norm"]   = df["CEP_Inicial"].apply(norm_cep)
    df["CEP_fim_norm"]   = df["CEP_Final"].apply(norm_cep)

    return df.reset_index(drop=True)

@st.cache_data(show_spinner=False)
def load_carteira(src):
    if isinstance(src, BytesIO): src.seek(0)
    df = pd.read_excel(src)
    df.columns = [c.strip() for c in df.columns]
    df["CPF/CNPJ"]  = df["CPF/CNPJ"].astype(str).str.strip()
    df["CNPJ_NORM"] = df["CPF/CNPJ"].apply(norm_cnpj)
    df["VENDEDOR"]  = df.get("VENDEDOR", pd.Series(dtype=str)).astype(str).str.strip()
    if "CEP" in df.columns:
        df["CEP_norm"] = df["CEP"].apply(norm_cep)
    return df

@st.cache_data(show_spinner=False)
def load_emplacamentos(src, label=""):
    if isinstance(src, BytesIO): src.seek(0)
    raw = pd.read_excel(src, header=None)
    header_row = 5
    for i in range(15):
        if any("Chassi" in str(v) for v in raw.iloc[i].tolist()):
            header_row = i; break
    if isinstance(src, BytesIO): src.seek(0)
    df = pd.read_excel(src, header=header_row)
    df.columns = [c.strip() for c in df.columns]
    df["_fonte"] = label
    for col in ["CPFCNPJPROPRIETARIO","NOMEPROPRIETARIO","NO_CIDADE","NO_BAIRRO","Placa","Chassi","Concessionário"]:
        if col in df.columns: df[col] = df[col].astype(str).str.strip()
    df["CNPJ_NORM"]     = df["CPFCNPJPROPRIETARIO"].apply(norm_cnpj)
    df["Data emplacamento"] = pd.to_datetime(df["Data emplacamento"], dayfirst=True, errors="coerce")
    df["Ano"]           = df["Data emplacamento"].dt.year
    df["Mes"]           = df["Data emplacamento"].dt.month
    df["Placa_norm"]    = df["Placa"].str.replace("-","").str.replace(" ","").str.upper()
    df["NO_CIDADE_NORM"]= df["NO_CIDADE"].apply(norm_str)
    df["NO_BAIRRO_NORM"]= df["NO_BAIRRO"].apply(lambda x: norm_str(x) if x not in ["nan","None"] else "")
    if "NU_CEP" in df.columns:
        df["CEP_norm"] = df["NU_CEP"].apply(norm_cep)
    else:
        df["CEP_norm"] = ""
    df.dropna(subset=["Ano"], inplace=True)
    df["Ano"] = df["Ano"].astype(int)
    return df

def merge_emp(dfs):
    m = pd.concat(dfs, ignore_index=True)
    m.drop_duplicates(subset=["Chassi"], keep="last", inplace=True)
    m.sort_values("Data emplacamento", inplace=True)
    return m

def get_consultor(cep_norm, cidade_norm, bairro_norm, df_area):
    """Retorna consultor por CEP (faixa) ou cidade+bairro como fallback."""
    if df_area is None: return None
    # 1. CEP
    if cep_norm and len(cep_norm) == 8:
        matches = df_area[
            (df_area["CEP_ini_norm"] != "") &
            (df_area["CEP_ini_norm"] <= cep_norm) &
            (df_area["CEP_fim_norm"] >= cep_norm)
        ]
        if not matches.empty:
            return matches.iloc[0]["Consultor"]
    # 2. Cidade + Bairro
    if bairro_norm:
        m = df_area[(df_area["Municipio_norm"] == cidade_norm) &
                    (df_area["Bairro_norm"].str.contains(bairro_norm[:10], na=False))]
        if not m.empty: return m.iloc[0]["Consultor"]
    m = df_area[df_area["Municipio_norm"] == cidade_norm]
    if not m.empty: return m.iloc[0]["Consultor"]
    return None

def get_munic_area(consultor, df_area):
    if df_area is None: return [], []
    sub = df_area[df_area["Consultor"] == consultor]
    municipios = sub["Municipio_norm"].unique().tolist()
    cep_ranges = sub[sub["CEP_ini_norm"] != ""][["CEP_ini_norm","CEP_fim_norm"]].values.tolist()
    return municipios, cep_ranges

def emp_da_area(df_emp, municipios, cep_ranges):
    if df_emp is None or df_emp.empty: return pd.DataFrame()
    # Normalizar municipios para comparação sem acento/espaço
    munic_set = set(municipios)
    # Também tentar sem espaços e abreviações comuns
    munic_set_alt = set()
    for m in municipios:
        munic_set_alt.add(m.replace(" ",""))
        munic_set_alt.add(re.sub(r'\bSAO\b','SAO',m))
        munic_set_alt.add(re.sub(r'\bSTO\b','SANTO',m))

    mask_cidade = df_emp["NO_CIDADE_NORM"].isin(munic_set)
    # fallback: comparação parcial para casos como "SAO PAULO" vs "SÃO PAULO" (já normalizados)
    if not mask_cidade.any() and municipios:
        mask_cidade = df_emp["NO_CIDADE_NORM"].apply(
            lambda c: any(c in m or m in c for m in munic_set) if c else False
        )

    if cep_ranges:
        mask_cep = pd.Series(False, index=df_emp.index)
        for ini, fim in cep_ranges:
            if ini and fim:
                mask_cep |= (
                    (df_emp["CEP_norm"] != "") &
                    (df_emp["CEP_norm"] >= ini) &
                    (df_emp["CEP_norm"] <= fim)
                )
        return df_emp[mask_cidade | mask_cep].copy()
    return df_emp[mask_cidade].copy()

